const ChatMessage = require('../models/ChatMessage');
const UserFollow = require('../models/UserFollow');
const Alliance = require('../models/Alliance');
const CacheService = require('../services/cacheService');

class ChatController {
  // 发送消息
  static async sendMessage(req, res) {
    try {
      const { channelType, channelId, content, metadata = {} } = req.body;
      const senderId = req.user.id;

      // 验证输入
      if (!channelType || !content) {
        return res.status(400).json({
          success: false,
          message: '频道类型和消息内容不能为空'
        });
      }

      // 验证频道权限
      if (channelType === 'alliance') {
        if (!channelId) {
          return res.status(400).json({
            success: false,
            message: '联盟频道需要指定联盟ID'
          });
        }
        
        // 检查用户是否在联盟中
        const userAlliance = await Alliance.getUserAlliance(senderId);
        if (!userAlliance || userAlliance.id !== channelId) {
          return res.status(403).json({
            success: false,
            message: '您不是该联盟的成员'
          });
        }
      } else if (channelType === 'private') {
        if (!channelId) {
          return res.status(400).json({
            success: false,
            message: '私聊需要指定接收者ID'
          });
        }
        
        // 检查是否互相关注
        const isFollowing = await UserFollow.isFollowing(senderId, channelId);
        const isFollowedBy = await UserFollow.isFollowing(channelId, senderId);
        
        if (!isFollowing || !isFollowedBy) {
          return res.status(403).json({
            success: false,
            message: '只能与互相关注的用户私聊'
          });
        }
      } else if (channelType === 'global') {
        // 全局消息需要管理员权限（这里简化处理）
        // 实际应该检查用户是否有管理员权限
        if (req.user.role !== 'admin') {
          return res.status(403).json({
            success: false,
            message: '只有管理员可以发送全局消息'
          });
        }
      }

      // 创建消息
      const message = await ChatMessage.create({
        senderId,
        channelType,
        channelId,
        content,
        metadata
      });

      // 创建未读消息记录
      await ChatMessage.createUnreadRecords(message.id, channelType, channelId, senderId);

      // 获取发送者信息
      const messageWithSender = {
        ...message,
        sender_name: req.user.username,
        sender_avatar: req.user.avatar_url
      };

      // 清除相关频道缓存
      const channelKey = `${channelType}:${channelId || 'global'}`;
      await CacheService.delPattern(`chat:${channelKey}:*`);

      res.status(201).json({
        success: true,
        message: '消息发送成功',
        data: messageWithSender
      });
    } catch (error) {
      console.error('发送消息失败:', error);
      res.status(500).json({
        success: false,
        message: '发送消息失败',
        error: error.message
      });
    }
  }

  // 获取频道消息 - 集成缓存优化
  static async getChannelMessages(req, res) {
    try {
      const { channelType, channelId } = req.params;
      const { page = 1, limit = 50 } = req.query;
      const offset = (page - 1) * limit;

      // 构建缓存键
      const channelKey = `${channelType}:${channelId || 'global'}`;
      const cacheKey = `chat:${channelKey}:${page}:${limit}`;

      // 先从缓存获取
      let messages = await CacheService.get(cacheKey);
      
      if (!messages) {
        // 从数据库获取
        messages = await ChatMessage.getChannelMessages(channelType, channelId, limit, offset);
        
        // 缓存结果（短期缓存，因为聊天消息更新频繁）
        await CacheService.set(cacheKey, messages, 300); // 5分钟缓存
      }

      res.json({
        success: true,
        data: messages,
        pagination: {
          page: parseInt(page),
          limit: parseInt(limit),
          offset
        }
      });
    } catch (error) {
      console.error('获取频道消息失败:', error);
      res.status(500).json({
        success: false,
        message: '获取频道消息失败',
        error: error.message
      });
    }
  }

  // 获取私聊消息
  static async getPrivateMessages(req, res) {
    try {
      const { userId } = req.params;
      const currentUserId = req.user.id;
      const { page = 1, limit = 50 } = req.query;
      const offset = (page - 1) * limit;

      // 构建缓存键
      const cacheKey = `private_chat:${currentUserId}:${userId}:${page}:${limit}`;

      // 先从缓存获取
      let messages = await CacheService.get(cacheKey);
      
      if (!messages) {
        // 从数据库获取私聊消息
        messages = await ChatMessage.getPrivateMessages(currentUserId, userId, limit, offset);
        
        // 缓存结果（短期缓存）
        await CacheService.set(cacheKey, messages, 300); // 5分钟缓存
      }

      res.json({
        success: true,
        data: messages,
        pagination: {
          page: parseInt(page),
          limit: parseInt(limit),
          offset
        }
      });
    } catch (error) {
      console.error('获取私聊消息失败:', error);
      res.status(500).json({
        success: false,
        message: '获取私聊消息失败',
        error: error.message
      });
    }
  }

  // 获取未读消息
  static async getUnreadMessages(req, res) {
    try {
      const { channelType, channelId } = req.params;
      const userId = req.user.id;
      const { page = 1, limit = 50 } = req.query;
      const offset = (page - 1) * limit;

      // 构建缓存键
      const channelKey = `${channelType}:${channelId || 'global'}`;
      const cacheKey = `unread_messages:${userId}:${channelKey}:${page}:${limit}`;

      // 先从缓存获取
      let messages = await CacheService.get(cacheKey);
      
      if (!messages) {
        // 从数据库获取未读消息
        messages = await ChatMessage.getUnreadMessages(userId, channelType, channelId, limit, offset);
        
        // 缓存结果（短期缓存）
        await CacheService.set(cacheKey, messages, 60); // 1分钟缓存
      }

      res.json({
        success: true,
        data: messages,
        pagination: {
          page: parseInt(page),
          limit: parseInt(limit),
          offset
        }
      });
    } catch (error) {
      console.error('获取未读消息失败:', error);
      res.status(500).json({
        success: false,
        message: '获取未读消息失败',
        error: error.message
      });
    }
  }

  // 搜索消息 - 集成缓存优化
  static async searchMessages(req, res) {
    try {
      const { channelType, channelId, query } = req.query;
      const { page = 1, limit = 20 } = req.query;
      const offset = (page - 1) * limit;

      // 构建缓存键
      const cacheKey = `chat_search:${channelType}:${channelId || 'global'}:${query}:${page}:${limit}`;

      // 先从缓存获取
      let results = await CacheService.get(cacheKey);
      
      if (!results) {
        // 从数据库搜索
        results = await ChatMessage.searchMessages(channelType, channelId, query, limit, offset);
        
        // 缓存搜索结果（短期缓存）
        await CacheService.set(cacheKey, results, 600); // 10分钟缓存
      }

      res.json({
        success: true,
        data: results,
        pagination: {
          page: parseInt(page),
          limit: parseInt(limit),
          offset
        }
      });
    } catch (error) {
      console.error('搜索消息失败:', error);
      res.status(500).json({
        success: false,
        message: '搜索消息失败',
        error: error.message
      });
    }
  }

  // 获取未读消息数 - 集成缓存优化
  static async getUnreadCount(req, res) {
    try {
      const userId = req.user.id;
      const { channelType, channelId } = req.query;

      // 构建缓存键
      const cacheKey = `unread_count:${userId}:${channelType}:${channelId || 'global'}`;

      // 先从缓存获取
      let count = await CacheService.get(cacheKey);
      
      if (count === null) {
        // 从数据库获取
        count = await ChatMessage.getUnreadCount(userId, channelType, channelId);
        
        // 缓存结果（短期缓存）
        await CacheService.set(cacheKey, count, 60); // 1分钟缓存
      }

      res.json({
        success: true,
        data: { count }
      });
    } catch (error) {
      console.error('获取未读消息数失败:', error);
      res.status(500).json({
        success: false,
        message: '获取未读消息数失败',
        error: error.message
      });
    }
  }

  // 标记消息为已读 - 清除相关缓存
  static async markAsRead(req, res) {
    try {
      const userId = req.user.id;
      const { messageIds, channelType, channelId } = req.body;

      if (messageIds && messageIds.length > 0) {
        await ChatMessage.markMessagesAsRead(userId, messageIds);
      } else if (channelType && channelId) {
        await ChatMessage.markChannelAsRead(userId, channelType, channelId);
      }

      // 清除相关缓存
      const channelKey = `${channelType}:${channelId || 'global'}`;
      await CacheService.delPattern(`unread_count:${userId}:${channelKey}`);
      await CacheService.delPattern(`chat:${channelKey}:*`);

      res.json({
        success: true,
        message: '标记已读成功'
      });
    } catch (error) {
      console.error('标记已读失败:', error);
      res.status(500).json({
        success: false,
        message: '标记已读失败',
        error: error.message
      });
    }
  }

  // 删除消息 - 清除相关缓存
  static async deleteMessage(req, res) {
    try {
      const { messageId } = req.params;
      const userId = req.user.id;

      const message = await ChatMessage.findById(messageId);
      if (!message) {
        return res.status(404).json({
          success: false,
          message: '消息不存在'
        });
      }

      // 检查权限（只有发送者可以删除）
      if (message.sender_id !== userId) {
        return res.status(403).json({
          success: false,
          message: '只能删除自己的消息'
        });
      }

      await ChatMessage.delete(messageId);

      // 清除相关缓存
      const channelKey = `${message.channel_type}:${message.channel_id || 'global'}`;
      await CacheService.delPattern(`chat:${channelKey}:*`);

      res.json({
        success: true,
        message: '消息删除成功'
      });
    } catch (error) {
      console.error('删除消息失败:', error);
      res.status(500).json({
        success: false,
        message: '删除消息失败',
        error: error.message
      });
    }
  }

  // 获取频道统计信息 - 集成缓存优化
  static async getChannelStats(req, res) {
    try {
      const { channelType, channelId } = req.params;

      // 构建缓存键
      const cacheKey = `channel_stats:${channelType}:${channelId || 'global'}`;

      // 先从缓存获取
      let stats = await CacheService.get(cacheKey);
      
      if (!stats) {
        // 从数据库获取
        stats = await ChatMessage.getChannelStats(channelType, channelId);
        
        // 缓存结果（较长时间缓存）
        await CacheService.set(cacheKey, stats, 1800); // 30分钟缓存
      }

      res.json({
        success: true,
        data: stats
      });
    } catch (error) {
      console.error('获取频道统计失败:', error);
      res.status(500).json({
        success: false,
        message: '获取频道统计失败',
        error: error.message
      });
    }
  }
}

module.exports = ChatController;
